import React, { useState, useEffect } from 'react';
import { Animated } from 'react-animated-css';

import Button from '../../components/buttons/Button';
import About from '../about/About';
import Skills from '../skills/Skills';
import Projects from '../projects/Projects';
import Project from '../project/Project';
import './Home.css';


const Home = () => {
    let mainContainer = React.createRef();
    let mainBtnsContainer = React.createRef();
    const mainBtnsDatas = [
        {
            btn: 'aboutBtn',
            btnName: 'About',
            btnClass: 'about-btn'
        },
        {
            btn: 'skillsBtn',
            btnName: 'Skills',
            btnClass: 'skills-btn'
        },
        {
            btn: 'projectsBtn',
            btnName: 'Projects',
            btnClass: 'projects-btn'
        }
    ];
    // const [mainBtnsDatas, setMainBtnsDatas] = useState([
    //     {
    //         btn: 'aboutBtn',
    //         btnName: 'About',
    //         btnClass: 'about-btn'
    //     },
    //     {
    //         btn: 'skillsBtn',
    //         btnName: 'Skills',
    //         btnClass: 'skills-btn'
    //     },
    //     {
    //         btn: 'projectsBtn',
    //         btnName: 'Projects',
    //         btnClass: 'projects-btn'
    //     }
    // ]);
    const [btnStatus, setBtnStatus] = useState({
        aboutBtn: false,
        skillsBtn: false,
        projectsBtn: false
    });
    const [contentCompShowStatus, setContentComponentShowStatus] = useState(false);
    const [currentContent, setCurrentContent] = useState(' ');
    const [firstTime, setFirstTime] = useState(true);
    // Temp
    const [btnContAdjStatus, setBtnContAdjStatus] = useState(false);
    const [contInAnima, setContInAnima] = useState(false);
    const [whichProjContainer, setWhichProjContainer] = useState(true);
    const [currentProject, setCurrentProject] = useState(null);
    const [windowWidth, setWindowWidth] = useState(null);
    const [checkMobileView, setCheckMobileView] = useState(false);
    useEffect(() => {
        creatContent();
        handleMobileContainerView();
    });
    useEffect(() => {
        const windowWidthFirstCheck = setTimeout(() => {
            currentWindowWidth();
        }, 100);
        window.addEventListener("resize", currentWindowWidth);
        return () => {
            window.removeEventListener("resize", currentWindowWidth);
            clearTimeout(windowWidthFirstCheck);
        }
    }, [windowWidth]);
    const handleOnClickChange = (clickBtnName) => {
        const btnPropArray = [];
        const falseBtnArray = [];
        for (let key in btnStatus) {
            if (btnStatus.hasOwnProperty(key)) {
                btnPropArray.push(key);
            }
        }
        btnPropArray.map((eachBtnProp, i) => {
            if (eachBtnProp !== clickBtnName) {
                falseBtnArray.push(eachBtnProp);
            }
            // Console shows up warning saying have to return
            return '';

        });
        const falseBtnOne = falseBtnArray[0];
        const falseBtnTwo = falseBtnArray[1];
        // console.log(falseBtnOne);
        // console.log(falseBtnTwo);
        setBtnStatus({
            [clickBtnName]: true,
            [falseBtnOne]: false,
            [falseBtnTwo]: false
        });
        // setTimeout(()=>{
        //     setPink(false);
        // },1000);
        setTimeout(() => {
            setWhichProjContainer(true);
        }, 500);
        containerAdjStart();
        delayContentContainer(1000);
        contentAnimationChange();
    }

    const creatContent = () => {
        if (contentCompShowStatus) {
            for (let key in btnStatus) {
                if (btnStatus.hasOwnProperty(key)) {
                    if (btnStatus[key] === true) {
                        if (key === 'aboutBtn') {
                            delayContent('about-contents');
                        } else if (key === 'skillsBtn') {
                            delayContent('skills-contents');
                        } else if (key === 'projectsBtn') {
                            delayContent('projects-contents');
                        }
                    }
                }
            }
        }
    }

    const delayContent = (content) => {
        if (firstTime) {
            setTimeout(() => {
                setCurrentContent(content);
                setFirstTime(false);
            }, 200);
        } else if (!firstTime) {
            setTimeout(() => {
                setCurrentContent(content);
            }, 450)

        }
    }

    const delayContentContainer = (second) => {
        if (!contentCompShowStatus) {
            setTimeout(() => {
                setContentComponentShowStatus(true);
            }, second)
        }
    }

    const containerAdjStart = () => {
        if (mainContainer) {
            setBtnContAdjStatus(true);
        }
    }

    const contentAnimationChange = () => {
        if (!contInAnima) {
            setContInAnima(true);
        } else if (contInAnima) {
            setContInAnima(false);
            setTimeout(() => {
                setContInAnima(true);
            }, 500);
        }
    }

    const handleDataRetrieve = (containerChange, projectData) => {
        setCurrentProject(projectData);
        setWhichProjContainer(containerChange);
    }

    const showCorrectProjContainer = () => {
        if (currentContent === "projects-contents") {
            if (whichProjContainer) {
                return <Projects projContainer={whichProjContainer} onClick={handleDataRetrieve} />;
            } else if (!whichProjContainer) {
                return <Project projData={currentProject} onClick={handleChangeContainer} />;
            }
        } else if (currentContent === "skills-contents") {
            return <Skills />;
        } else if (currentContent === "about-contents") {
            return <About />;
        }
    }

    const handleChangeContainer = (clicked) => {
        if (clicked) {
            setWhichProjContainer(true);
        }
    }

    const currentWindowWidth = () => {
        const desktopView = (window.innerWidth < 1000);
        setWindowWidth(desktopView);
    }

    const handleMobileContainerView = () => {
        console.log(windowWidth);
        if(windowWidth && btnContAdjStatus){
            setCheckMobileView(true);
        }else if(!windowWidth){
            setCheckMobileView(false);   
        }
    }


    return (
        <div className="home">
        {/* {checkMobileView? 'home-mobile-view' : 'home'} */}
            <div className="main-container" ref={mainContainer}>
            {/* {btnContAdjStatus ? `main-container expand-active` : "main-container"} */}
                <div className={btnContAdjStatus ? `main-btns-container shrink-active` : "main-btns-container"} ref={mainBtnsContainer} >
                
                    <Button btnDatas={mainBtnsDatas} parentContainer={mainBtnsContainer} onClick={handleOnClickChange} />
                </div>
                {contentCompShowStatus &&
                    <div className="main-contents-container">
                        <Animated className="content-animate-container" animationIn="zoomIn" animationOut="zoomOut" isVisible={contInAnima} animationInDelay={!firstTime ? 0 : 400}>
                            <div className="content">

                                {showCorrectProjContainer()}



                            </div>
                        </Animated>
                    </div>
                }

            </div>
        </div>
    )
}

export default Home;


