import React, { useState, Fragment } from 'react';
import { CSSTransition } from 'react-transition-group';
import './Button.css';

const Button = ({ btnDatas, onClick, parentContainer }) => {
    const previousClasses = ['about-btn', 'skills-btn', 'projects-btn'];
    const [classExist, setClassExist] = useState(false);

    const handleStateChange = (e) => {
        e.persist();
        e.stopPropagation();
        e.preventDefault();
        // console.log(e.target);
        onClick(e.target.classList[1]);
        adjButtonPosition(e.target)
    }

    const adjButtonPosition = (buttonEl) => {
        previousClasses.map((previousClass) => {
            const containClass = buttonEl.classList.contains(previousClass);
            if (containClass) {
                setClassExist(true);
            }
            return '';
        });
    }


    return (
        <Fragment>
            {btnDatas.map((btnData, i) => {

                return (<CSSTransition key={i} in={classExist} timeout={1200} classNames={btnData.btnClass}>

                    <button
                        key={i}
                        className={classExist ? `${btnData.btnClass}-reposition ${btnData.btn} main-btn` : `${btnData.btnClass} ${btnData.btn} main-btn original-btn`}
                        onClick={handleStateChange}
                    >{btnData.btnName}
                    </button>

                </CSSTransition>)

            })}
        </Fragment>
    )
}

export default Button;


